  1→import { Component, type ErrorInfo, type ReactNode } from 'react';
  2→import { WarningIcon } from '../icons';
  3→import './error_boundary.scss';
  4→
  5→interface ErrorBoundaryProps {
  6→  children: ReactNode;
  7→  onReset?: () => void;
  8→}
  9→
 10→interface ErrorBoundaryState {
 11→  error: Error | null;
 12→  showDetails: boolean;
 13→}
 14→
 15→export class ErrorBoundary extends Component<
 16→  ErrorBoundaryProps,
 17→  ErrorBoundaryState
 18→> {
 19→  state: ErrorBoundaryState = {
 20→    error: null,
 21→    showDetails: false,
 22→  };
 23→
 24→  static getDerivedStateFromError(error: Error): Partial<ErrorBoundaryState> {
 25→    return { error };
 26→  }
 27→
 28→  componentDidCatch(error: Error, info: ErrorInfo) {
 29→    console.error('[ErrorBoundary] Uncaught error:', error);
 30→    if (info.componentStack) {
 31→      console.error('[ErrorBoundary] Component stack:', info.componentStack);
 32→    }
 33→  }
 34→
 35→  private handleRetry = () => {
 36→    this.props.onReset?.();
 37→    this.setState({
 38→      error: null,
 39→      showDetails: false,
 40→    });
 41→  };
 42→
 43→  private handleToggleDetails = () => {
 44→    this.setState(prev => ({ showDetails: !prev.showDetails }));
 45→  };
 46→
 47→  private handleKeyDown = (e: React.KeyboardEvent) => {
 48→    if (e.key === 'Escape') {
 49→      e.preventDefault();
 50→      e.stopPropagation();
 51→      this.handleRetry();
 52→    }
 53→  };
 54→
 55→  render() {
 56→    if (!this.state.error) {
 57→      return this.props.children;
 58→    }
 59→
 60→    const { error, showDetails } = this.state;
 61→    const errorMessage = error.message || 'An unexpected error occurred';
 62→    const errorStack = error.stack;
 63→
 64→    return (
 65→      <div
 66→        className="error-boundary"
 67→        role="alert"
 68→        onKeyDown={this.handleKeyDown}
 69→      >
 70→        <div className="error-boundary__content">
 71→          <div className="error-boundary__icon">
 72→            <WarningIcon size={32} />
 73→          </div>
 74→          <h2 className="error-boundary__title">Something went wrong</h2>
 75→          <p className="error-boundary__message">{errorMessage}</p>
 76→          {errorStack && (
 77→            <>
 78→              <button
 79→                type="button"
 80→                className="error-boundary__toggle"
 81→                onClick={this.handleToggleDetails}
 82→                aria-expanded={showDetails}
 83→              >
 84→                {showDetails ? 'Hide Details' : 'Show Details'}
 85→              </button>
 86→              {showDetails && (
 87→                <pre className="error-boundary__stack">{errorStack}</pre>
 88→              )}
 89→            </>
 90→          )}
 91→          <div className="error-boundary__actions">
 92→            <button
 93→              type="button"
 94→              className="error-boundary__button"
 95→              onClick={this.handleRetry}
 96→              autoFocus
 97→            >
 98→              Try Again
 99→            </button>
100→          </div>
101→        </div>
102→      </div>
103→    );
104→  }
105→}
