  1→import { useCallback, useState } from 'react';
  2→import { NavViewData, TRAY_COMMAND_MAP } from './app_types';
  3→import { ActionPanel } from './components/action_panel/action_panel';
  4→import { CommandPalette } from './components/command_palette/command_palette';
  5→import { DetailItemView } from './components/detail/detail_item_view';
  6→import { ErrorBoundary } from './components/error_boundary/error_boundary';
  7→import { Kbd } from './components/kbd/kbd';
  8→import { RootSearchView } from './components/root_search';
  9→import { SearchBar } from './components/search_bar/search_bar';
 10→import {
 11→  NavigationContextProvider,
 12→  useNavigationStack,
 13→} from './hooks/use_navigation';
 14→import { useRecentCommands } from './hooks/use_recent_commands';
 15→import { useTheme } from './hooks/use_theme';
 16→import { useWindow } from './hooks/use_window';
 17→import { getCommand } from './registry';
 18→
 19→function renderNavView(data: NavViewData) {
 20→  if (data.type === 'command') {
 21→    const cmd = getCommand(data.commandId);
 22→    if (cmd?.component) {
 23→      const Component = cmd.component;
 24→      return <Component />;
 25→    }
 26→    return null;
 27→  }
 28→
 29→  if (data.type === 'detail') {
 30→    return <DetailItemView item={data.item} />;
 31→  }
 32→
 33→  return null;
 34→}
 35→
 36→export function App() {
 37→  useTheme();
 38→  const nav = useNavigationStack<NavViewData>('Raycast');
 39→  const { push, popToRoot } = nav;
 40→  const { addRecent } = useRecentCommands();
 41→  const [isCompact, setIsCompact] = useState(true);
 42→  const [rootResetKey, setRootResetKey] = useState(0);
 43→
 44→  const handleTrayNavigate = useCallback(
 45→    (target: string) => {
 46→      const mapping = TRAY_COMMAND_MAP[target];
 47→      if (!mapping) return;
 48→
 49→      const cmd = getCommand(mapping.id);
 50→      if (!cmd?.component) return;
 51→
 52→      popToRoot();
 53→      addRecent(mapping.id);
 54→      push(mapping.name, {
 55→        type: 'command',
 56→        commandId: mapping.id,
 57→      });
 58→    },
 59→    [
 60→      push,
 61→      popToRoot,
 62→      addRecent,
 63→    ],
 64→  );
 65→
 66→  useWindow({
 67→    onShow: () => {
 68→      const input =
 69→        document.querySelector<HTMLInputElement>('.search-bar__input');
 70→      input?.focus();
 71→    },
 72→    onHide: () => {
 73→      popToRoot();
 74→      setRootResetKey(k => k + 1);
 75→    },
 76→    onTrayNavigate: handleTrayNavigate,
 77→  });
 78→
 79→  const currentNavData = nav.currentEntry?.data;
 80→  const isFullView =
 81→    currentNavData?.type === 'command' &&
 82→    (getCommand(currentNavData.commandId)?.fullView ?? false);
 83→
 84→  const navDirectionClass =
 85→    nav.direction === 'push'
 86→      ? ' command-palette__nav-view--push'
 87→      : nav.direction === 'pop'
 88→        ? ' command-palette__nav-view--pop'
 89→        : '';
 90→
 91→  const isRoot = !currentNavData;
 92→  const compact = isRoot && isCompact;
 93→
 94→  const contextLabel =
 95→    nav.breadcrumbs.length > 0
 96→      ? nav.breadcrumbs[nav.breadcrumbs.length - 1]!.label
 97→      : 'Raycast';
 98→
 99→  return (
100→    <NavigationContextProvider value={nav}>
101→      <CommandPalette isLoading compact={compact}>
102→        {isFullView && nav.currentEntry ? (
103→          <ErrorBoundary key={nav.navKey} onReset={nav.pop}>
104→            <div className={`command-palette__nav-view${navDirectionClass}`}>
105→              {renderNavView(nav.currentEntry.data)}
106→            </div>
107→          </ErrorBoundary>
108→        ) : nav.currentEntry ? (
109→          <>
110→            <SearchBar
111→              value=""
112→              onChange={() => {}}
113→              breadcrumbs={
114→                nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined
115→              }
116→            />
117→            <ErrorBoundary key={nav.navKey} onReset={nav.pop}>
118→              <div className={`command-palette__nav-view${navDirectionClass}`}>
119→                <div className="command-palette__body">
120→                  <div className="command-palette__list-container">
121→                    {renderNavView(nav.currentEntry.data)}
122→                  </div>
123→                </div>
124→              </div>
125→            </ErrorBoundary>
126→            <ActionPanel
127→              contextLabel={contextLabel}
128→              actions={[
129→                {
130→                  label: 'Open',
131→                  shortcut: <Kbd keys={['↵']} />,
132→                },
133→              ]}
134→              dropdownOpen={false}
135→              dropdownSections={[]}
136→              onDropdownClose={() => {}}
137→            />
138→          </>
139→        ) : (
140→          <RootSearchView key={rootResetKey} onCompactChange={setIsCompact} />
141→        )}
142→      </CommandPalette>
143→    </NavigationContextProvider>
144→  );
145→}
